sql:
SELECT beneficiary_name, age
FROM beneficiaries
WHERE gender = 'Male';

SELECT MAX(population) 
FROM mouzas 
WHERE mouza_name = 'Ailakandi';

SELECT population 
FROM mouzas 
WHERE mouza_id = 1;

SELECT sales.sale_id, beneficiaries.email
FROM sales
INNER JOIN beneficiaries ON sales.beneficiary_id = beneficiaries.beneficiary_id;

SELECT district_name
FROM districts
WHERE population > (SELECT AVG(population) FROM districts);

SELECT COUNT(*) 
FROM beneficiary_training 
WHERE status = 'completed';

SELECT beneficiary_name
FROM beneficiaries
WHERE beneficiary_id = 1;

SELECT block_id, AVG(population) AS average_population
FROM mouzas
GROUP BY block_id;

SELECT COUNT(*) 
FROM beneficiaries 
WHERE age >= 50;

SELECT 
  (SELECT SUM(total_amount) FROM sales) AS total_sales,
  (SELECT SUM(cost) FROM training_programs) AS total_training_cost;

SELECT COUNT(*) 
FROM beneficiary_trades 
WHERE end_date IS NULL;

SELECT beneficiary_name 
FROM beneficiaries 
ORDER BY beneficiary_name;

